pub fn is_complex_unit(parts: &[RawEntityPart]) -> bool {
    !parts.is_empty()
        && parts
            .iter()
            .all(|p| COMPLEX_PART_NAMES.contains(&p.name.as_str()))
}

pub fn in_subset(ent: &RawEntity) -> bool {
    match ent {
        RawEntity::Simple { name, .. } => SIMPLE_NAMES.contains(&name.as_str()),
        RawEntity::Complex { parts, .. } => is_complex_unit(parts),
    }
}

